import React from "react";
import './project2.css'

function Project2() {
    return (
      <div id="project2-body">
          <h4>Fitness Tracker</h4>
          <p id="project2-description">
            A REACT app that allows users to register an account, build fitness routines, create custom workouts, and browse ro and buy and sell items on the marketplace. Tech stack: REACT, JSON, HTML, REST API, HTML/CSS, Material UI.
          </p>
          <div>
            <ul id="project2-links-ul">
                <li id="project2-link1"><a id="project1-link1" href="https://wonderful-baklava-d81c60.netlify.app">View Site</a></li>
                <li id="project2-link2"><a id="project1-link2" href="https://github.com/ameyer12/FitnessTrackrFrontEnd">GitHub</a></li>
            </ul>
          </div>
      </div>
    )
  }

export default Project2;
